#include <bits/stdc++.h>
using namespace std;
int n,ans,a[1000006],mark[1000006];
bool flag=true;
int main(){
    //cout<<mark[10]<<endl;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=30;i>=0;i--){
        int sum=0;
        ans+=(1<<i);
        //cout<<(1<<i)<<endl;
        for(int j=1;j<=n;j++){
            if((a[j] & ans)>=ans){
            	sum++;
            	//cout<<sum<<endl;
			}
        }
        if(sum<2){
        	ans-=(1<<i);
		}
    }
    cout<<ans;
    return 0;
}
